/* 文件头注释：说明核心算法名称和关键技术 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;
const int MAXN = 500010;

vector<int> tree[MAXN];
int a[MAXN];
int lcm[MAXN];

// 计算最小公倍数
long long computeLCM(long long a, long long b) {
    return a / __gcd(a, b) * b;
}

// DFS遍历树，计算每个子树的最小过载周期
void dfs(int u) {
    lcm[u] = a[u];
    for (int v : tree[u]) {
        dfs(v);
        lcm[u] = computeLCM(lcm[u], lcm[v]) % MOD;
    }
}

int main() {
    int n, q;
    scanf("%d%d", &n, &q);
    for (int i = 1; i <= n; ++i) {
        scanf("%d", &a[i]);
    }
    for (int i = 2; i <= n; ++i) {
        int parent;
        scanf("%d", &parent);
        tree[parent].push_back(i);
    }

    // 预处理每个子树的最小过载周期
    dfs(1);

    int lastans = 0;
    while (q--) {
        int x;
        scanf("%d", &x);
        int u = (x + lastans) % n + 1;
        lastans = lcm[u];
        printf("%d\n", lastans);
    }

    return 0;
}
```

### 代码说明：
1. **computeLCM函数**：计算两个数的最小公倍数，使用`__gcd`函数计算最大公约数，然后根据公式`LCM(a, b) = a * b / GCD(a, b)`计算最小公倍数。
2. **dfs函数**：深度优先搜索遍历树，计算每个子树的最小过载周期。对于每个节点，其子树的最小过载周期是其自身周期与所有子节点子树的最小过载周期的最小公倍数。
3. **主函数**：读取输入数据，构建树结构，调用`dfs`函数预处理每个子树的最小过载周期，然后处理每个查询，根据地址偏移计算查询的子树，并输出结果。

### 复杂度分析：
- **时间复杂度**：预处理阶段为O(N)，查询阶段为O(Q)，总时间复杂度为O(N + Q)。
- **空间复杂度**：O(N)，用于存储树的结构和每个子树的最小过载周期。

### 边界情况与潜在陷阱：
- 树的根节点是1，且树的结构不会产生环。
- 查询时需要考虑地址偏移，即上一次查询的答案。
